consumption.cssSetup:
Import tokens CSS at your app entry point: import '@ds-mo/tokens/css';
This provides all var(--color-*), var(--dimension-*), var(--effect-*), and var(--typography-*) custom properties.
For dark mode, set data-theme="dark" on <html>.

files.content:
/**
 * Surface — lean container primitive.
 * Backgrounds, elevation, edges, radius, and interactive states.
 * Hover/pressed via direct background-color + color-mix(). No pseudo-element overlays.
 */

.surface {
  box-sizing: border-box;
  position: relative;
  /* Reset native button/anchor chrome when rendered as those elements */
  border: none;
  padding: 0;
  margin: 0;
  font: inherit;
  color: inherit;
  background: none;
  text-decoration: none;
  text-align: left;
  cursor: default;
  appearance: none;
  -webkit-appearance: none;
}

/* ==========================================================================
   Backgrounds
   ========================================================================== */

.bgPrimary {
  background-color: var(--color-background-primary);
}

.bgSecondary {
  background-color: var(--color-background-secondary);
}

.bgTransparent {
  background-color: transparent;
}

.bgTranslucent {
  background-color: var(--color-background-translucent);
  backdrop-filter: blur(var(--effect-blur-md));
  -webkit-backdrop-filter: blur(var(--effect-blur-md));
}

/* ==========================================================================
   Semantic Intent Backgrounds — intent{Intent}{Contrast}
   ========================================================================== */

/* Brand */
.intentBrandFaint { background-color: var(--color-background-faint-brand); }
.intentBrandMedium { background-color: var(--color-background-medium-brand); }
.intentBrandBold { background-color: var(--color-background-bold-brand); }
.intentBrandStrong { background-color: var(--color-background-strong-brand); }

/* Positive */
.intentPositiveFaint { background-color: var(--color-background-faint-positive); }
.intentPositiveMedium { background-color: var(--color-background-medium-positive); }
.intentPositiveBold { background-color: var(--color-background-bold-positive); }
.intentPositiveStrong { background-color: var(--color-background-strong-positive); }

/* Negative */
.intentNegativeFaint { background-color: var(--color-background-faint-negative); }
.intentNegativeMedium { background-color: var(--color-background-medium-negative); }
.intentNegativeBold { background-color: var(--color-background-bold-negative); }
.intentNegativeStrong { background-color: var(--color-background-strong-negative); }

/* Warning */
.intentWarningFaint { background-color: var(--color-background-faint-warning); }
.intentWarningMedium { background-color: var(--color-background-medium-warning); }
.intentWarningBold { background-color: var(--color-background-bold-warning); }
.intentWarningStrong { background-color: var(--color-background-strong-warning); }

/* Caution */
.intentCautionFaint { background-color: var(--color-background-faint-caution); }
.intentCautionMedium { background-color: var(--color-background-medium-caution); }
.intentCautionBold { background-color: var(--color-background-bold-caution); }
.intentCautionStrong { background-color: var(--color-background-strong-caution); }

/* AI */
.intentAiFaint { background-color: var(--color-background-faint-ai); }
.intentAiMedium { background-color: var(--color-background-medium-ai); }
.intentAiBold { background-color: var(--color-background-bold-ai); }
.intentAiStrong { background-color: var(--color-background-strong-ai); }

/* Neutral */
.intentNeutralFaint { background-color: var(--color-background-faint-neutral); }
.intentNeutralMedium { background-color: var(--color-background-medium-neutral); }
.intentNeutralBold { background-color: var(--color-background-bold-neutral); }
.intentNeutralStrong { background-color: var(--color-background-strong-neutral); }

/* Walkthrough */
.intentWalkthroughFaint { background-color: var(--color-background-faint-walkthrough); }
.intentWalkthroughMedium { background-color: var(--color-background-medium-walkthrough); }
.intentWalkthroughBold { background-color: var(--color-background-bold-walkthrough); }
.intentWalkthroughStrong { background-color: var(--color-background-strong-walkthrough); }

/* Guide */
.intentGuideFaint { background-color: var(--color-background-faint-guide); }
.intentGuideMedium { background-color: var(--color-background-medium-guide); }
.intentGuideBold { background-color: var(--color-background-bold-guide); }
.intentGuideStrong { background-color: var(--color-background-strong-guide); }

/* ==========================================================================
   Elevation — progressive: none → flat → elevated → floating
   ========================================================================== */

.elevationNone {}

.elevationDepressed {
  box-shadow: var(--effect-elevation-depressed-sm);
}

.elevationDepressedMd {
  box-shadow: var(--effect-elevation-depressed-md);
}

.elevationFlat {
  box-shadow: var(--effect-elevation-elevated-sm);
}

.elevationElevated {
  box-shadow: var(--effect-elevation-elevated-md);
}

.elevationFloating {
  box-shadow: var(--effect-elevation-elevated-floating);
}

.elevationOverlayTop {
  box-shadow: var(--effect-elevation-elevated-panel-top);
}

.elevationOverlayRight {
  box-shadow: var(--effect-elevation-elevated-panel-right);
}

.elevationOverlayBottom {
  box-shadow: var(--effect-elevation-elevated-panel-bottom);
}

.elevationOverlayLeft {
  box-shadow: var(--effect-elevation-elevated-panel-left);
}

/* ==========================================================================
   Edge Borders (only when elevation='none')
   ========================================================================== */

.edgeTop { border-top: var(--dimension-stroke-width-015) solid var(--color-border-tertiary); }
.edgeRight { border-right: var(--dimension-stroke-width-015) solid var(--color-border-tertiary); }
.edgeBottom { border-bottom: var(--dimension-stroke-width-015) solid var(--color-border-tertiary); }
.edgeLeft { border-left: var(--dimension-stroke-width-015) solid var(--color-border-tertiary); }

/* ==========================================================================
   Corner Radius
   ========================================================================== */

.radiusNone { border-radius: var(--dimension-radius-000); }
.radiusXs { border-radius: var(--dimension-radius-050); }
.radiusSm { border-radius: var(--dimension-radius-075); }
.radiusMd { border-radius: var(--dimension-radius-100); }
.radiusLg { border-radius: var(--dimension-radius-125); }
.radiusXl { border-radius: var(--dimension-radius-175); }
.radius2xl { border-radius: var(--dimension-radius-200); }
.radiusFull { border-radius: var(--dimension-radius-half); }

/* ==========================================================================
   Interactive States — direct background-color, no pseudo-elements
   ========================================================================== */

.interactive {
  cursor: pointer;
  transition: transform var(--effect-motion-short-2);

  /* Interaction — ghost defaults */
  --_hover-bg: var(--color-interaction-hover);
  --_pressed-bg: var(--color-interaction-pressed);
}

.interactive:hover {
  background-color: var(--_hover-bg);
}

.interactive:active {
  background-color: var(--_pressed-bg);
  transform: scale(var(--dimension-scale-subtle));
}

.interactive:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-space-025);
}

/* ==========================================================================
   Selected State — persistent overlay on any background via ::before
   ========================================================================== */

.selected::before {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  pointer-events: none;
  z-index: 0;
  background-color: var(--color-interaction-hover);
}

.selected > * {
  position: relative;
  z-index: 1;
}

/* ==========================================================================
   Inactive State
   ========================================================================== */

.inactive {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

import React, { forwardRef } from 'react';
import styles from './Surface.module.css';

/**
 * Semantic intent for colored surfaces.
 * Each intent has four contrast levels (faint, medium, bold, strong).
 */
export type SurfaceIntent =
  | 'brand'
  | 'positive'
  | 'negative'
  | 'warning'
  | 'caution'
  | 'ai'
  | 'neutral'
  | 'walkthrough'
  | 'guide';

/** Background type for non-intent surfaces. */
export type SurfaceBackground = 'primary' | 'secondary' | 'transparent' | 'translucent';

/** Contrast level for semantic intents. */
export type SurfaceContrast = 'faint' | 'medium' | 'bold' | 'strong';

/** Elevation for depth/shadow effects. Progressive: none → flat → elevated → floating. */
export type SurfaceElevation =
  | 'none'
  | 'depressed'
  | 'depressed-md'
  | 'flat'
  | 'elevated'
  | 'floating'
  | 'overlayTop'
  | 'overlayRight'
  | 'overlayBottom'
  | 'overlayLeft';

/** Edge divider border direction. */
export type SurfaceEdge = 'top' | 'right' | 'bottom' | 'left';

/** Corner radius presets. */
export type SurfaceRadiusPreset = 'none' | 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl' | 'full';

/** Corner radius — preset, CSS variable, or custom string (e.g. '12px 12px 0 0'). */
export type SurfaceRadius = SurfaceRadiusPreset | (string & {});

/** HTML elements Surface can render as. */
export type SurfaceElement =
  | 'div'
  | 'section'
  | 'aside'
  | 'article'
  | 'header'
  | 'footer'
  | 'main'
  | 'nav'
  | 'span'
  | 'button'
  | 'td'
  | 'th';

/** Props shared by both surface modes. */
interface SurfaceBaseProps extends React.HTMLAttributes<HTMLElement> {
  children?: React.ReactNode;
  /** Elevation for depth/shadow effects. Defaults to 'none'. */
  elevation?: SurfaceElevation;
  /** Edge divider border(s). Only applies when elevation is 'none'. */
  edge?: SurfaceEdge | SurfaceEdge[];
  /** Corner radius — preset or CSS variable. */
  radius?: SurfaceRadius;
  /** Enable hover/pressed interaction overlay. */
  interactive?: boolean;
  /** Apply selected background state. */
  selected?: boolean;
  /** Dim and disable pointer events. */
  inactive?: boolean;
  /** HTML element to render. Defaults to 'div'. */
  as?: SurfaceElement;
  /** Button type — only used when as='button'. */
  type?: 'button' | 'submit' | 'reset';
}

/** Non-intent surface — uses a basic background color. */
interface SurfaceDefaultProps extends SurfaceBaseProps {
  /** Background color. Defaults to 'transparent'. */
  background?: SurfaceBackground;
  intent?: never;
  contrast?: never;
}

/** Intent surface — uses a semantic color with contrast level. */
interface SurfaceIntentProps extends SurfaceBaseProps {
  /** Semantic intent color. */
  intent: SurfaceIntent;
  /** Contrast level for the intent background. Defaults to 'faint'. */
  contrast?: SurfaceContrast;
  background?: never;
}

export type SurfaceProps = SurfaceDefaultProps | SurfaceIntentProps;

const backgroundClassMap: Record<SurfaceBackground, string> = {
  primary: styles.bgPrimary,
  secondary: styles.bgSecondary,
  transparent: styles.bgTransparent,
  translucent: styles.bgTranslucent,
};

const elevationClassMap: Record<SurfaceElevation, string> = {
  none: styles.elevationNone,
  depressed: styles.elevationDepressed,
  'depressed-md': styles.elevationDepressedMd,
  flat: styles.elevationFlat,
  elevated: styles.elevationElevated,
  floating: styles.elevationFloating,
  overlayTop: styles.elevationOverlayTop,
  overlayRight: styles.elevationOverlayRight,
  overlayBottom: styles.elevationOverlayBottom,
  overlayLeft: styles.elevationOverlayLeft,
};

const edgeClassMap: Record<SurfaceEdge, string> = {
  top: styles.edgeTop,
  right: styles.edgeRight,
  bottom: styles.edgeBottom,
  left: styles.edgeLeft,
};

const radiusClassMap: Record<SurfaceRadiusPreset, string> = {
  none: styles.radiusNone,
  xs: styles.radiusXs,
  sm: styles.radiusSm,
  md: styles.radiusMd,
  lg: styles.radiusLg,
  xl: styles.radiusXl,
  '2xl': styles.radius2xl,
  full: styles.radiusFull,
};

const getIntentContrastClass = (intent: SurfaceIntent, contrast: SurfaceContrast): string => {
  const intentKey = intent.charAt(0).toUpperCase() + intent.slice(1);
  const contrastKey = contrast.charAt(0).toUpperCase() + contrast.slice(1);
  return styles[`intent${intentKey}${contrastKey}`] || '';
};

const isPresetRadius = (radius: SurfaceRadius): radius is SurfaceRadiusPreset =>
  radius in radiusClassMap;

export const Surface = forwardRef<HTMLElement, SurfaceProps>(
  (
    {
      children,
      background = 'transparent',
      intent,
      contrast = 'faint',
      elevation = 'none',
      edge,
      radius,
      interactive = false,
      selected = false,
      inactive = false,
      as: Component = 'div',
      className = '',
      style,
      type,
      ...rest
    },
    ref
  ) => {
    const classes = [
      styles.surface,
      // Background or intent+contrast
      intent
        ? getIntentContrastClass(intent, contrast)
        : backgroundClassMap[background],
      // Elevation
      elevationClassMap[elevation],
      // Edge(s) — only when elevation is 'none'
      ...(edge && elevation === 'none'
        ? Array.isArray(edge)
          ? edge.map(e => edgeClassMap[e])
          : [edgeClassMap[edge]]
        : []),
      // Radius (preset only — custom handled via inline style)
      radius && isPresetRadius(radius) ? radiusClassMap[radius] : '',
      // States
      interactive ? styles.interactive : '',
      selected ? styles.selected : '',
      inactive ? styles.inactive : '',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    const computedStyle: React.CSSProperties = {
      ...style,
      ...(radius && !isPresetRadius(radius) ? { borderRadius: radius } : {}),
    };

    const hasStyle =
      (radius && !isPresetRadius(radius)) || (style && Object.keys(style).length > 0);

    const elementProps = {
      ref,
      className: classes,
      style: hasStyle ? computedStyle : undefined,
      disabled: Component === 'button' ? inactive : undefined,
      type: Component === 'button' ? type || 'button' : undefined,
      ...rest,
    };

    return (
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      <Component {...(elementProps as any)}>{children}</Component>
    );
  }
);

Surface.displayName = 'Surface';
